+#[test]
+fn terminal_app_prompts_to_close_reviewed_patch_chat_and_reopens_on_typing() {
+    let root = git_repo("terminal-app-reviewed-patch-close");
+    fs::write(root.join("README.md"), "before\n").unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["add", "README.md"])
+        .status()
+        .unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["commit", "-m", "ADD initial readme fixture"])
+        .status()
+        .unwrap();
+
+    let backend = FakeBackend::new([
+        "patch ready\n@work-leaf patch update readme\n--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-before\n+after\n@work-leaf end\n@work-leaf done",
+        "summary: README changes from before to after",
+        "NO_FINDINGS",
+        "follow-up reply",
+    ]);
+    let chat = CommandChat::new(root, backend.clone()).with_max_review_rounds(4);
+    let mut app = TerminalApp::new(chat, 100, 24);
+
+    app.handle_bytes(b":new update readme\n");
+    assert!(app.wait_for_idle(Duration::from_secs(2)));
+
+    assert_eq!(
+        app.ui().selected_agent().map(AgentId::as_str),
+        Some("user-1")
+    );
+    let reviewed_frame = app.render_frame();
+    assert!(reviewed_frame.contains("user-1 reviewed by review-user-1: rounds=1 resolved=yes"));
+    assert!(reviewed_frame.contains("work-leaf: is this feature done? yes/no"));
+    assert!(app.ui().render_left_pane().contains("user-1  working"));
+    assert!(app.ui().render_left_pane().contains("READY"));
+
+    app.handle_bytes(b"yes\n");
+
+    assert!(!app.ui().render_left_pane().contains("user-1  working"));
+    assert!(
+        !backend
+            .sends()
+            .iter()
+            .any(|(_, prompt)| prompt.trim() == "yes"),
+        "closing a reviewed chat should not resume the agent"
+    );
+
+    app.handle_bytes(b"please take another pass\n");
+    assert!(app.wait_for_idle(Duration::from_secs(1)));
+
+    assert!(app.ui().render_left_pane().contains("user-1  working"));
+    let reopened_frame = app.render_frame();
+    assert!(reopened_frame.contains("user: please take another pass"));
+    assert!(reopened_frame.contains("follow-up reply"));
+    assert!(backend.sends().iter().any(|(agent_id, prompt)| {
+        agent_id.as_str() == "user-1" && prompt == "please take another pass"
+    }));
+}
