use std::collections::BTreeSet;

use crate::{
    AgentId, AgentListEntry, PaneFocus, TerminalUi, UiKey, UiMode,
    chat_title::{ChatTitleAgent, fallback_chat_title_from_prompt},
    workspace::FEATURE_DONE_PROMPT,
